export async function PATCH(request: Request) {
  try {
    // 1. Verificar sesi├│n de Supabase
    const cookieStore = await cookies()
    const supabase = createServerClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
      {
        cookies: {
          getAll() { return cookieStore.getAll() },
          setAll() {}
        },
      }
    )

    const { data: { user } } = await supabase.auth.getUser()
    if (!user && process.env.NODE_ENV === 'production') {
       return NextResponse.json({ error: 'No autorizado' }, { status: 401 })
    }

    // 2. Capturar Payload
    const { productId, descriptionLong } = await request.json()

    if (!productId) {
      return NextResponse.json({ error: 'Falta el ID del producto' }, { status: 400 })
    }

    // 3. Persistencia en DB
    const updatedProduct = await prisma.product.update({
      where: { id: productId },
      data: { descriptionLong }
    })

    return NextResponse.json({ success: true, product: updatedProduct })
  } catch (error: any) {
    console.error('API /admin/catalogo PATCH Error:', error)
    return NextResponse.json({ error: 'Fallo al guardar la rese├▒a' }, { status: 500 })
  }
}

