interface CatalogAddToCartProps {
  product: {
    id: string
    name: string
    price: number
    imageUrl?: string | null
    stock: number // Referencia para futuras validaciones si se desea
  }
  storeSlug: string
}

export function CatalogAddToCart({ product, storeSlug }: CatalogAddToCartProps) {
  const addItem = useCartStore(state => state.addItem)

  const handleAddToCart = (e: MouseEvent<HTMLButtonElement>) => {
    e.preventDefault() // Detener la navegaci├│n del <Link> envolvente
    e.stopPropagation() // Evitar propagaci├│n al contenedor

    addItem({
      id: product.id,
      name: product.name,
      price: product.price,
      quantity: 1,
      imageUrl: product.imageUrl
    })
  }

  return (
    <button 
      onClick={handleAddToCart}
      className="bg-slate-900 text-white p-2 border border-slate-900 rounded-xl hover:bg-white hover:text-slate-900 transition-colors active:scale-95 shadow-sm"
